INSERT INTO public.latex_symbols VALUES (6937, '0', '0', 'basic', '数字 0', '单独使用数字：$0$；或者在指数中：$x^0=1$。', 1, '0');
INSERT INTO public.latex_symbols VALUES (6938, '1', '1', 'basic', '数字 1', '乘法恒等元：$a \\cdot 1 = a$。', 2, '1');
INSERT INTO public.latex_symbols VALUES (6939, '2', '2', 'basic', '数字 2', '常用作指数：$a^2$ 表示 a 的平方。', 3, '2');
INSERT INTO public.latex_symbols VALUES (6940, '3', '3', 'basic', '数字 3', '立方根示例：$\\sqrt[3]{x}$。', 4, '3');
INSERT INTO public.latex_symbols VALUES (6941, '4', '4', 'basic', '数字 4', '四则运算：$2 + 2 = 4$。', 5, '4');
INSERT INTO public.latex_symbols VALUES (6942, '5', '5', 'basic', '数字 5', '数字 5：$f^{(5)}(x)$ 表示 5 阶导数。', 6, '5');
INSERT INTO public.latex_symbols VALUES (6943, '6', '6', 'basic', '数字 6', '组合数示例：$\\binom{6}{2}$。', 7, '6');
INSERT INTO public.latex_symbols VALUES (6944, '7', '7', 'basic', '数字 7', '数字 7：$x = 7$。', 8, '7');
INSERT INTO public.latex_symbols VALUES (6945, '8', '8', 'basic', '数字 8', '数字 8：$2^3 = 8$。', 9, '8');
INSERT INTO public.latex_symbols VALUES (6946, '9', '9', 'basic', '数字 9', '数字 9：$\\sqrt{81} = 9$。', 10, '9');
INSERT INTO public.latex_symbols VALUES (6947, '!', '!', 'punctuation', '感叹号 / 阶乘符号', '用于表示阶乘：$n! = 1 \\cdot 2 \\cdot \\ldots \\cdot n$。', 11, '!');
INSERT INTO public.latex_symbols VALUES (6948, '#', '\#', 'basic', '井号 / 宏参数符', '在定义宏时使用：`\\newcommand{\\foo}[1]{#1}`。直接显示源字符需使用 `\\#`。', 12, '#');
INSERT INTO public.latex_symbols VALUES (6949, '$', '\$', 'delimiter', '美元符号 / 公式定界符', '用于进入数学模式：$x+y$ 为行内公式。显示美元符号需使用 `\\$`。', 13, '$');
INSERT INTO public.latex_symbols VALUES (6950, '%', '\%', 'punctuation', '百分号 / 注释符', 'LaTeX 中 % 用于单行注释。显示百分号需使用 `\\%`。', 14, '%');
INSERT INTO public.latex_symbols VALUES (6951, '&', '\&', 'punctuation', '和符号 / 对齐符', '用于表格或对齐环境（如 align）：`a & = b`。显示和符号需使用 `\\&`。', 15, '&');
INSERT INTO public.latex_symbols VALUES (6952, '(', '(', 'delimiter', '左圆括号', '基本用法：$(a+b)$；适应高度用法：`\\left( \\frac{1}{x} \\right)`。', 16, '(');
