INSERT INTO public.problems VALUES ('8b8e96b2-14a5-4fed-8377-d4101d6a9b1b', 'LaTeX 基本文档类声明', '请写出LaTeX文档的起始命令，使用article文档类，并设置字体大小为12pt。', 'latex_input', 'easy', 10, NULL, '\documentclass[12pt]{article}', '每个LaTeX文档都以\\documentclass命令开头，可选参数[12pt]指定正文字体大小。', NULL, 10, 'published', '2beeba13-943c-4b7c-908d-97f999d58c90', 1, 1, '2026-02-19 16:31:48.82751+08', '2026-02-19 16:31:48.82751+08');
INSERT INTO public.problems VALUES ('3a4e83ae-bd51-4a22-9ed8-651c362c0916', '创建章节标题', '请写出创建“引言”章节的一级标题命令。', 'latex_input', 'easy', 10, NULL, '\section{引言}', '\\section 自动编号并生成目录条目。', NULL, 10, 'published', '2beeba13-943c-4b7c-908d-97f999d58c90', 1, 0, '2026-02-19 16:31:48.82751+08', '2026-02-19 16:31:48.82751+08');
INSERT INTO public.problems VALUES ('bd5449d0-4f06-4b2f-915e-8c309d32c348', '生成标题页', '写出定义标题、作者、日期并生成标题页的完整命令序列（标题“我的第一篇论文”，作者“李四”）。', 'latex_input', 'medium', 10, NULL, '\title{我的第一篇论文}
\author{李四}
\date{\today}
\maketitle', '\\title、\\author、\\date 定义元数据，\\maketitle 输出标题页。', NULL, 10, 'published', '2beeba13-943c-4b7c-908d-97f999d58c90', 0, 0, '2026-02-19 16:31:48.82751+08', '2026-02-19 16:31:48.82751+08');
