INSERT INTO public.tool_recommendations VALUES (31, 'Overleaf Learn LaTeX', '最受欢迎的在线 LaTeX 编辑器 + 完整教程库，从“30分钟入门”到表格、图表、参考文献等高级主题，全部支持一键在 Overleaf 中编辑运行。', 'https://www.overleaf.com/learn', 'tutorial', NULL, NULL, true, 1, NULL, '2026-02-19 02:44:27.461145+08', '入门到高级');
INSERT INTO public.tool_recommendations VALUES (32, 'Learn LaTeX (learnlatex.org)', 'LaTeX 项目团队成员亲自编写的 16 节短课，内容精炼、可直接在线编辑示例，安装+基础+结构一步步教。', 'https://www.learnlatex.org/en/', 'tutorial', NULL, NULL, true, 2, NULL, '2026-02-19 02:44:27.461145+08', '入门');
INSERT INTO public.tool_recommendations VALUES (33, 'LaTeX-Tutorial.com', '简洁清晰的步步教程，配完整代码示例，专为科研论文/报告设计，适合快速上手。', 'https://latex-tutorial.com/', 'tutorial', NULL, NULL, false, 3, NULL, '2026-02-19 02:44:27.461145+08', '入门 / 进阶');
INSERT INTO public.tool_recommendations VALUES (34, 'UseOctree Learn LaTeX', '2025 年更新的完整初学者教程，覆盖文档结构、数学公式、表格、引用等，界面现代。', 'https://www.useoctree.com/learn/latex', 'tutorial', NULL, NULL, false, 4, NULL, '2026-02-19 02:44:27.461145+08', '入门');
INSERT INTO public.tool_recommendations VALUES (35, 'Javatpoint LaTeX Tutorial', '结构化教程 + 大量示例代码，适合有编程基础的初学者，包含环境搭建和常用命令。', 'https://www.javatpoint.com/latex-tutorial', 'tutorial', NULL, NULL, false, 5, NULL, '2026-02-19 02:44:27.461145+08', '入门');
INSERT INTO public.tool_recommendations VALUES (36, 'LaTeX Wikibooks', '开放式维基百科风格的全面手册，从零基础到高级宏、自定义样式，几乎所有主题都有。', 'https://en.wikibooks.org/wiki/LaTeX', 'reference', NULL, NULL, true, 6, NULL, '2026-02-19 02:44:27.461145+08', '入门到高级');
INSERT INTO public.tool_recommendations VALUES (37, 'Getting to Grips with LaTeX', '经典免费教程，内容平衡，适合从入门过渡到进阶的科研写作。', 'http://www.andy-roberts.net/writing/latex', 'tutorial', NULL, NULL, false, 7, NULL, '2026-02-19 02:44:27.461145+08', '入门到进阶');
INSERT INTO public.tool_recommendations VALUES (38, 'The LaTeX Project 官方文档', 'LaTeX 核心团队维护的官方参考文档、发布说明和进阶指南。', 'https://www.latex-project.org/help/documentation/', 'reference', NULL, NULL, true, 8, NULL, '2026-02-19 02:44:27.461145+08', '进阶到高级');
INSERT INTO public.tool_recommendations VALUES (39, 'TeX Users Group (TUG)', 'TeX/LaTeX 官方用户组织，提供资源链接、会议资料、新闻和进一步学习路径。', 'https://www.tug.org/', 'community', NULL, NULL, false, 9, NULL, '2026-02-19 02:44:27.461145+08', '所有层次');
INSERT INTO public.tool_recommendations VALUES (40, 'CTAN - 综合 TeX 档案网', '所有 LaTeX 包的中央仓库，可搜索包名、下载文档，是进阶必备工具站。', 'https://www.ctan.org/', 'tool', NULL, NULL, true, 10, NULL, '2026-02-19 02:44:27.461145+08', '高级');
INSERT INTO public.tool_recommendations VALUES (41, 'TeX - LaTeX Stack Exchange', '全球最大的 LaTeX 问答社区，搜任何问题几乎都有答案，包含高级宏、排版技巧。', 'https://tex.stackexchange.com/', 'community', NULL, NULL, false, 11, NULL, '2026-02-19 02:44:27.461145+08', '进阶到高级');
INSERT INTO public.tool_recommendations VALUES (42, 'Detexify', '“手画符号找命令”神器，画出符号就能得到 LaTeX 代码 + 所需包，学习符号最快方式。', 'https://detexify.kirelabs.org/', 'tool', NULL, NULL, true, 12, NULL, '2026-02-19 02:44:27.461145+08', '所有层次');
INSERT INTO public.tool_recommendations VALUES (43, 'TeXample.net', '海量 LaTeX 示例库（尤其是 TikZ/PGF 绘图），适合想做复杂图表/海报的进阶用户。', 'https://www.texample.net/', 'reference', NULL, NULL, false, 13, NULL, '2026-02-19 02:44:27.461145+08', '进阶到高级');
INSERT INTO public.tool_recommendations VALUES (44, 'Harvard Library LaTeX Resources', '顶尖大学图书馆整理的资源合集，包含模板、符号列表、进阶链接，质量极高。', 'https://guides.library.harvard.edu/overleaf/latex', 'reference', NULL, NULL, false, 14, NULL, '2026-02-19 02:44:27.461145+08', '入门到进阶');
INSERT INTO public.tool_recommendations VALUES (45, 'The Not So Short Introduction', '经典“不太短的 LaTeX 介绍”（lshort）官方托管站点，PDF + 更新链接，进阶必读。', 'https://tobi.oetiker.ch/lshort/', 'tutorial', NULL, NULL, false, 15, NULL, '2026-02-19 02:44:27.461145+08', '入门到进阶');


